local ngx = ngx;
ngx.req.read_body();  -- parse the request body in the beginning to prevent error in case of large file upload
local cjson = require('cjson');    -- for parsing json content type. use json for simplicity, json format is more strict than xml api. but they are both standard
local xml2json = require "lxml";   -- parse xml from request body and convert to json 
local http_xml_req = ngx.req.get_body_data();    -- get the request body in XML format (if you have not set it by ngx.req.set_header('Content-Type','application/xml') then you will need to parse this content type )  
if xml2json ~= nil  then
    local json = cjson.encode(xml2json);    -- if the request body is xml, convert to json.
    ngx.say("Request is of xml and it converted into JSON.") 
    ngx.header.content_type="text/plain"      -- set the response content type as text for simplicity in example. It would not matter because this will not be consumed by lua. but if you have html content, set the content type accordingly (example : application/xml).
    ngx.say(json); 
    ngx.exit(200)                             -- send the response to client with 200 status code. (for simplicity in example)
else 
    ngx.header.content_type="application/json"    --  set the response content type as JSON so that json parser will be able to read the body
    ngx.say("Request is of text and it converted into JSON.")
    local json = cjson.encode(ngx.req.get_uri_args());   -- get all URI params (if the request method was GET )
    ngx.header.content_type="text/plain"      -- set response content type as text for simplicity in example. But you can also set it to application/xml, application/json and any other format here. 
